  ('social-worker-moex-00291', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「孩童出生於貧困和家長未受教育的家庭，可能面臨債務、有限的經驗和機會，以及較差的教育、 健康照顧等，這些都會阻礙他們在生活中獲取成功的能力」。這樣的觀點基於下列何種理論？', '["功能論", "衝突理論", "文化理論", "符號互動論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00292', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '性別歧視，尤其是制度性歧視，造成許多女性落入貧窮循環之中，同工不同酬是工作職場中常見 的性別歧視。有關同工不同酬的現象，下列敘述何者錯誤？', '["性別之間的薪資差異只存在在專業工程領域", "在以性別為主導的職業中，薪資差異仍然存在", "薪資不平等的影響自女性進入職場直到退休始終存在", "隨著工作經驗及升遷，女性的薪資會逐年增加，但女性常因照顧責任而需暫離工作職場"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00293', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者是代間社會流動的例子？', '["孩子超越家長的階級", "人的階級地位由於投資不善而改變", "商業成功的結果是改變人的階級地位", "生完孩子後，一對伴侶的階級地位下降"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00294', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據艾力克森（Erikson）的理論，心理社會發展的階段順利時，會呈現出熱愛家庭、關懷社會， 有責任心、有正義感，是下列那一階段？', '["青少年時期", "成年早期", "成年中期", "成年晚期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00295', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '一位被醫師診斷出罹患癌症的住院高齡案主，案主擔憂地詢問主治醫師
病況，但是主要照顧的伴侶卻堅持拜託醫師目前先不要告訴案主詳細實
情，以免打擊案主。主治醫師與醫務社會工作者應在病人自主權利法的
脈絡下與病患及家人討論病情。試從倫理理論分析社會工作者將面臨什
麼價值倫理議題？以及宜依循那些倫理抉擇步驟進行決策？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00296', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '在衛生福利部推動的強化社會安全網第二期計畫 110～114 年中，策略
二「優化保護服務輸送，提升風險控管」的主要目標之一為降低兒虐致
死人數，兒虐致死人數每年低於 0.01%。試從兒少保護社會工作者的立
場，說明應如何運用那些策略來有效地降低兒虐致死率？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00297', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會福利從慈善到公民權利的發展歷程有幾個重要的轉折，下列敘述何者錯誤？', '["貝佛里奇報告（TheBeveridgeReport）放棄資產調查的社會救助，規劃社會保險", "新政（TheNewDeal）實施改變了濟貧由地方辦理的觀念，促成美國的社會安全法案", "史賓漢蘭制（SpeenhamlandSystem）提出救助基礎的依據", "新濟貧法主張救濟設施應因地制宜，濟貧所內收容人的待遇應低於一般工人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00298', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依長期照顧十年計畫2.0「社區整體照顧服務體系」之規劃，服務於「社區整合型服務中心」的社 會工作者，其主要專業角色為下列何者？', '["個案管理者", "照顧服務督導員", "專業輔導人員", "團體活動規劃者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00299', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會工作專業教育的發展，下列敘述何者不符合當前趨勢？', '["透過社會工作實習制度，提升學生於理論與實務方面的整合能力", "證照制度的實施造成人才的斷層與壟斷，應加以廢除", "社會工作應兼具國際化與國情化，以提升專業性", "社會工作應落實以證據為基礎的實務實施"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00300', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關臺灣社會工作專業發展取得法治基礎的重要事件，下列何者正確？', '["1980年制定「兒童福利法」", "1997年公布實施「社會工作師法」", "2002年修訂「身心障礙者權益保障法」", "2009年公布實施「專科社工甄審及教育辦法」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
